namespace BgControls.Windows.DragDrop;/// <summary>/// 拖拽装饰器控件，用于在拖拽操作期间提供视觉反馈和效果展示./// </summary>public class DragDecorator : ContentControl{    /// <summary>    /// 反向缩放变换依赖属性.    /// </summary>    public static readonly DependencyProperty ReverseZoomTransformProperty =        DependencyProperty.Register("ReverseZoomTransform", typeof(Transform), typeof(DragDecorator), new PropertyMetadata(null));    /// <summary>    /// 相对起始点依赖属性.    /// </summary>    public static readonly DependencyProperty RelativeStartPointProperty =        DependencyProperty.Register("RelativeStartPoint", typeof(Point), typeof(DragDecorator), new PropertyMetadata(null));    /// <summary>    /// 拖拽视觉偏移依赖属性.    /// </summary>    public static readonly DependencyProperty DragVisualOffsetProperty =        DependencyProperty.Register("DragVisualOffset", typeof(Point), typeof(DragDecorator), null);    /// <summary>    /// 拖拽放置效果依赖属性.    /// </summary>    public static readonly DependencyProperty EffectsProperty =        DependencyProperty.Register("Effects", typeof(DragDropEffects), typeof(DragDecorator), new PropertyMetadata(DragDropEffects.All | DragDropEffects.Link, OnEffectsPropertyChanged));    /// <summary>    /// 是否使用默认光标依赖属性.    /// </summary>    public static readonly DependencyProperty UseDefaultCursorsProperty =        DependencyProperty.Register("UseDefaultCursors", typeof(bool), typeof(DragDecorator), new PropertyMetadata(true));    /// <summary>    /// Initializes static members of the <see cref="DragDecorator"/> class.    /// </summary>    static DragDecorator()    {        // 覆盖默认样式键以确保正确加载控件模板.        DefaultStyleKeyProperty.OverrideMetadata(typeof(DragDecorator), new FrameworkPropertyMetadata(typeof(DragDecorator)));    }    /// <summary>    /// Initializes a new instance of the <see cref="DragDecorator"/> class.    /// </summary>    public DragDecorator()    {        // 订阅加载完成事件以初始化视觉状态.        this.Loaded += this.OnDragDecoratorLoaded;    }    /// <summary>    /// Gets or sets 反向缩放变换.    /// </summary>    public Transform ReverseZoomTransform    {        get { return (Transform)this.GetValue(ReverseZoomTransformProperty); }        set { this.SetValue(ReverseZoomTransformProperty, value); }    }    /// <summary>    /// Gets or sets 拖拽视觉偏移.    /// </summary>    public Point DragVisualOffset    {        get { return (Point)this.GetValue(DragVisualOffsetProperty); }        set { this.SetValue(DragVisualOffsetProperty, value); }    }    /// <summary>    /// Gets or sets 相对起始点.    /// </summary>    public Point RelativeStartPoint    {        get { return (Point)this.GetValue(RelativeStartPointProperty); }        set { this.SetValue(RelativeStartPointProperty, value); }    }    /// <summary>    /// Gets or sets 拖拽放置效果.    /// </summary>    public DragDropEffects Effects    {        get { return (DragDropEffects)this.GetValue(EffectsProperty); }        set { this.SetValue(EffectsProperty, value); }    }    /// <summary>    /// Gets or sets a value indicating whether 是否使用默认光标.    /// </summary>    public bool UseDefaultCursors    {        get { return (bool)this.GetValue(UseDefaultCursorsProperty); }        set { this.SetValue(UseDefaultCursorsProperty, value); }    }    /// <summary>    /// 应用控件模板时的处理逻辑.    /// </summary>    public override void OnApplyTemplate()    {        base.OnApplyTemplate();        // 首次应用模板时更新视觉状态，不启用过渡动画.        this.UpdateVisualStates(false);    }    /// <summary>    /// 当 Effects 属性更改时的静态回调.    /// </summary>    private static void OnEffectsPropertyChanged(DependencyObject d, DependencyPropertyChangedEventArgs e)    {        if (d is DragDecorator decorator)        {            // 调用实例方法处理属性变更逻辑.            decorator.HandleEffectsChanged();        }    }    /// <summary>    /// 响应 Effects 属性更改的实例方法.    /// </summary>    private void HandleEffectsChanged()    {        // 当效果变更时，启用过渡动画更新视觉状态.        this.UpdateVisualStates(true);    }    /// <summary>    /// 根据当前属性状态更新控件的视觉状态.    /// </summary>    /// <param name="useTransitions">是否使用视觉状态过渡动画.</param>    private void UpdateVisualStates(bool useTransitions)    {        // 检查是否需要展示内置的拖拽状态反馈.        if (this.UseDefaultCursors)        {            if ((this.Effects & DragDropEffects.Link) == DragDropEffects.Link)            {                VisualStateManager.GoToState(this, DragDropEffects.Link.ToString(), useTransitions);            }            else if ((this.Effects & DragDropEffects.Move) == DragDropEffects.Move)            {                VisualStateManager.GoToState(this, DragDropEffects.Move.ToString(), useTransitions);            }            else if ((this.Effects & DragDropEffects.Copy) == DragDropEffects.Copy)            {                VisualStateManager.GoToState(this, DragDropEffects.Copy.ToString(), useTransitions);            }            else            {                // 注意：此处保持了原有的 0 == 0 逻辑分支结构.                if (0 == 0)                {                    VisualStateManager.GoToState(this, DragDropEffects.None.ToString(), useTransitions);                }                else if ((this.Effects & DragDropEffects.Scroll) == DragDropEffects.Scroll)                {                    VisualStateManager.GoToState(this, DragDropEffects.Scroll.ToString(), useTransitions);                }            }        }        else        {            // 隐藏状态标识.            VisualStateManager.GoToState(this, "Hidden", useTransitions);        }        // 如果内容是 IEffectsPresenter 接口的实现类，则同步更新其效果.        if (this.Content is IEffectsPresenter effectsPresenter)        {            effectsPresenter.Effects = this.Effects;        }    }    /// <summary>    /// 响应控件加载完成事件.    /// </summary>    private void OnDragDecoratorLoaded(object sender, RoutedEventArgs e)    {        // 加载完成后立即刷新视觉状态.        this.UpdateVisualStates(false);    }    /// <summary>    /// 初始化控件时的处理逻辑.    /// </summary>    /// <param name="e">事件参数.</param>    protected override void OnInitialized(EventArgs e)    {        base.OnInitialized(e);    }}